{
  "title": "DBMS Introduction and Architecture Quiz",
  "difficulty": "medium",
  "questions": [
    {
      "id": "q1",
      "question": "Which of the following best describes 'Information' according to the class notes?",
      "options": {
        "A": "Raw, unorganized facts and details like symbols",
        "B": "Data measured strictly in bits and bytes",
        "C": "Processed data that provides context and enables decision-making",
        "D": "A collection of unrelated data points without significance"
      },
      "answer": "C",
      "explanation": "Information is processed, organized, and structured data that makes sense and allows for decision-making."
    },
    {
      "id": "q2",
      "question": "In the Three-Schema Architecture, which level is responsible for describing 'what' data is stored and the relationships among that data?",
      "options": {
        "A": "Physical level",
        "B": "Logical level",
        "C": "Internal level",
        "D": "External level"
      },
      "answer": "B",
      "explanation": "The logical (conceptual) level describes the design of the database, the data stored, and their relationships."
    },
    {
      "id": "q3",
      "question": "Which of these is identified as a disadvantage of traditional file-processing systems?",
      "options": {
        "A": "Data Abstraction",
        "B": "Atomicity problems",
        "C": "Efficient data retrieval",
        "D": "Personalized user views"
      },
      "answer": "B",
      "explanation": "File-processing systems suffer from several issues including redundancy, inconsistency, and atomicity problems."
    },
    {
      "id": "q4",
      "question": "What is the primary goal of the Physical level of abstraction in a DBMS?",
      "options": {
        "A": "To provide different views to different end-user groups",
        "B": "To define the relationships between data entities",
        "C": "To describe how data is actually stored using low-level structures",
        "D": "To allow the DBA to decide what information to keep"
      },
      "answer": "C",
      "explanation": "The physical level is the lowest level of abstraction and describes physical storage and data structures."
    },
    {
      "id": "q5",
      "question": "A collection of information stored in a database at a specific moment in time is known as a(n):",
      "options": {
        "A": "Schema",
        "B": "Subschema",
        "C": "Instance",
        "0": "Internal level"
      },
      "answer": "B",
      "explanation": "An instance refers to the specific collection of information stored in the database at any given moment."
    },
    {
      "id": "q6",
      "question": "According to the class notes, hair color and gender are examples of which type of data?",
      "options": {
        "A": "Quantitative data",
        "B": "Information points",
        "C": "Qualitative data",
        "D": "Numerical data"
      },
      "answer": "C",
      "explanation": "Qualitative data is descriptive and non-numerical, such as names, gender, or hair color."
    },
    {
      "id": "q7",
      "question": "Which level of the Three-Schema Architecture provides a security mechanism to prevent users from accessing certain parts of the database?",
      "options": {
        "A": "View level",
        "B": "Physical level",
        "C": "Internal level",
        "D": "Logical level"
      },
      "answer": "A",
      "explanation": "The View level (external level) uses subschemas to hide certain parts of the database for security and personalization."
    },
    {
      "id": "q8",
      "question": "Which of the following is a key difference between Data and Information?",
      "options": {
        "A": "Information is raw facts, while data is processed",
        "B": "Data depends on information to exist",
        "C": "Information depends on data, but data does not depend on information",
        "D": "Data is used for decision-making, while information is not"
      },
      "answer": "C",
      "explanation": "The notes state that while information depends on data, data does not depend on information."
    }
  ]
}
